INSERT INTO `chart_of_accounts` VALUES (1049,'504fe000-aafa-42f4-beff-c50bcb69e3ef',6,'Aset','Header',1,'1-0000','','ASET','Debit','Aset adalah semua kekayaan yang dimiliki atau digunakan BUMDes untuk menjalankan usaha. Aset dapat berupa uang, barang, bangunan, kendaraan, maupun alat kerja. Semua aset membantu kegiatan operasional dan menghasilkan manfaat ekonomi bagi BUMDes.',1,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1050,'1add557d-d349-4f5f-b1f0-d0fdf5e85727',6,'Aset','Header',2,'1-1000','1-0000','Aset Lancar','Debit','Aset lancar adalah aset yang mudah digunakan, dicairkan, atau habis dalam waktu dekat. Aset ini biasanya dipakai untuk kebutuhan operasional harian usaha. Contohnya kas, saldo bank, piutang, dan persediaan barang.',2,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1051,'db0aa858-9ace-4ece-b53a-4f784599b8aa',6,'Aset','Header',3,'1-1100','1-1000','Kas dan Setara Kas','Debit','Akun ini digunakan untuk mencatat seluruh uang tunai dan saldo rekening yang dimiliki BUMDes. Dana pada kelompok ini dapat digunakan kapan saja untuk kegiatan usaha. Kas dan setara kas menjadi dasar utama kelancaran operasional harian.',3,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1052,'f6131bb8-7b0b-4f38-b97c-62e15695279e',6,'Aset','Detail',4,'1-1110','1-1100','Kas','Debit','Kas adalah uang tunai yang tersedia langsung di BUMDes. Uang ini biasanya disimpan oleh bendahara, kasir, atau kantor operasional. Kas digunakan untuk pembayaran dan penerimaan transaksi sehari-hari.',4,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1053,'16433ad7-f61d-4d41-b089-cddeec7dde86',6,'Aset','Header',4,'1-1200','1-1100','Bank','Debit','Akun ini digunakan untuk mencatat seluruh dana yang disimpan di rekening bank. Setiap transaksi transfer masuk dan keluar akan tercatat dalam akun ini. Penggunaan rekening bank membantu pengelolaan keuangan lebih aman dan transparan.',5,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1054,'81ba6434-3d6b-4db2-b6a1-92ab741d1e16',6,'Aset','Detail',5,'1-1210','1-1200','Bank BRI','Debit','Akun ini mencatat seluruh saldo dan transaksi pada rekening Bank BRI milik BUMDes. Semua penerimaan dan pengeluaran melalui rekening tersebut dicatat agar sesuai dengan mutasi bank. Pemisahan rekening membantu laporan keuangan menjadi lebih jelas.',6,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1055,'68db90ec-7654-46d5-b1d9-b1d096abf35d',6,'Aset','Detail',5,'1-1211','1-1200','Bank Jatim','Debit','Akun ini digunakan untuk mencatat transaksi yang menggunakan rekening Bank Jatim. Dana yang tersimpan pada rekening ini biasanya digunakan untuk kegiatan operasional atau unit usaha tertentu. Akun ini membantu mempermudah pengawasan arus kas usaha.',7,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1056,'99afeba8-bc2a-4c0f-b1f0-822d90c6aeb9',6,'Aset','Detail',5,'1-1212','1-1200','Bank Mandiri','Debit','Akun ini digunakan untuk mencatat saldo dan transaksi pada rekening Bank Mandiri milik BUMDes. Setiap transaksi yang terjadi melalui rekening ini akan mempengaruhi saldo akun. Pencatatan terpisah membuat pengelolaan keuangan lebih tertib dan mudah diperiksa.',8,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1057,'3441f643-64a9-43d8-8d41-ea70c6ea4d20',6,'Aset','Header',3,'1-1300','1-1000','Piutang Usaha','Debit','Piutang usaha adalah tagihan kepada pelanggan atau warga yang belum membayar transaksi. Piutang muncul karena penjualan dilakukan secara tempo atau pembayaran ditunda. Akun ini membantu BUMDes memantau jumlah uang yang masih harus diterima.',9,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1058,'83b92708-4fc3-4f3e-9bdc-82a2318dc235',6,'Aset','Detail',4,'1-1310','1-1300','Piutang Usaha','Debit','Akun ini digunakan untuk mencatat nilai tagihan usaha yang belum dibayar pelanggan. Semakin besar nilai piutang, semakin besar pula dana yang masih berada di pihak luar. Piutang perlu dikontrol agar tidak menjadi kerugian bagi usaha.',10,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1059,'19cb8e22-1ed3-4f7d-86b7-e0f5a1d6095a',6,'Aset','Detail',4,'1-1320','1-1300','Penyisihan Piutang Tak Tertagih','Kredit','Akun ini digunakan sebagai cadangan atas piutang yang kemungkinan sulit ditagih. Tujuannya agar laporan keuangan tetap realistis dan tidak terlalu tinggi mencatat aset. Akun ini membantu BUMDes lebih siap menghadapi risiko kerugian piutang.',11,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1060,'d0cbd80c-fa99-4de4-8852-dcc59bf0d351',6,'Aset','Header',3,'1-1400','1-1000','Persediaan','Debit','Persediaan adalah stok barang atau hasil usaha yang dimiliki BUMDes untuk dijual atau digunakan dalam kegiatan usaha. Jumlah persediaan akan berubah ketika ada pembelian atau penjualan barang. Pengelolaan persediaan yang baik membantu usaha berjalan lancar dan mengurangi risiko kehilangan barang.',12,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1061,'c74ee50c-a22a-4cf7-b317-82aa0732f5e2',6,'Aset','Detail',4,'1-1410','1-1400','Persediaan Barang Dagangan','Debit','Akun ini digunakan untuk mencatat stok barang yang dibeli untuk dijual kembali tanpa proses produksi. Contohnya sembako, pupuk, gas LPG, dan barang minimarket desa. Persediaan ini menjadi sumber utama penjualan pada usaha perdagangan.',13,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1062,'6b955aa0-37b9-4a58-9cf5-109d092c8854',6,'Aset','Detail',4,'1-1420','1-1400','Persediaan Barang Jadi','Debit','Akun ini digunakan untuk mencatat hasil produksi yang sudah selesai dan siap dijual. Contohnya telur, keripik, kopi desa, atau produk olahan lainnya. Barang jadi menjadi sumber pendapatan bagi unit produksi BUMDes.',14,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1063,'8a9d3cd6-8aca-4542-99ca-5873116d3563',6,'Aset','Detail',4,'1-1440','1-1400','Persediaan Lainnya','Debit','Akun ini digunakan untuk mencatat persediaan lain yang belum termasuk kategori utama. Biasanya digunakan untuk kebutuhan unit usaha tertentu yang memiliki stok khusus. Akun ini membantu pencatatan persediaan menjadi lebih fleksibel.',15,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1064,'d2cd029f-54b0-4028-9ae6-8a025308bb5d',6,'Aset','Header',3,'1-1500','1-1000','Aset Lancar Non-Persediaan','Debit','Akun ini digunakan untuk mengelompokkan aset lancar selain kas, piutang, dan persediaan. Aset dalam kelompok ini tetap digunakan dalam operasional sehari-hari. Pengelompokan ini membantu laporan keuangan lebih rapi dan mudah dipahami.',16,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1065,'f9c07402-4ade-46ed-87ec-f555977a3651',6,'Aset','Detail',4,'1-1510','1-1500','Perlengkapan','Debit','Perlengkapan adalah barang kecil yang digunakan untuk kegiatan operasional sehari-hari. Contohnya alat tulis, kertas, tinta printer, sapu, dan alat kebersihan. Nilai perlengkapan akan berkurang seiring penggunaan.',17,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1066,'175ed0b2-c434-43b6-93a0-575a487fa5a8',6,'Aset','Detail',4,'1-1520','1-1500','Biaya Dibayar di Muka','Debit','Akun ini digunakan untuk biaya yang sudah dibayar sekarang tetapi manfaatnya digunakan pada periode berikutnya. Contohnya sewa bangunan tahunan atau pembayaran asuransi. Akun ini membantu agar biaya dicatat sesuai masa manfaat penggunaannya.',18,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1067,'ab4b6ad7-3255-4612-b6ea-4cad8fb0d5a3',6,'Aset','Detail',3,'1-1530','1-1000','Aset Lancar Lainnya','Debit','Akun ini digunakan untuk mencatat aset lancar lain yang belum memiliki kelompok khusus. Biasanya digunakan untuk kebutuhan tambahan sesuai kondisi usaha desa. Akun ini membuat sistem pencatatan lebih fleksibel mengikuti kebutuhan BUMDes.',19,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1068,'0888b0de-eddc-4c7b-a96b-9fae8398141f',6,'Aset','Header',2,'1-2000','1-0000','Aset Tetap','Debit','Aset tetap adalah aset yang digunakan dalam jangka panjang untuk mendukung operasional usaha. Aset ini tidak untuk dijual kembali dalam kegiatan normal usaha. Contohnya bangunan, kendaraan, mesin, dan inventaris kantor.',20,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1069,'e626c053-38ee-4369-88ce-8d58d9162070',6,'Aset','Detail',3,'1-2010','1-2000','Tanah','Debit','Akun ini digunakan untuk mencatat tanah milik atau yang digunakan BUMDes. Tanah dapat digunakan untuk lokasi usaha, gudang, toko, atau fasilitas desa lainnya. Nilai tanah biasanya tetap dan tidak mengalami penyusutan seperti aset lainnya.',21,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1070,'8eb1a882-a7c3-4bae-9c12-10955447deb0',6,'Aset','Detail',3,'1-2020','1-2000','Bangunan','Debit','Akun ini digunakan untuk mencatat bangunan yang dipakai dalam kegiatan usaha BUMDes. Contohnya toko desa, kantor, gudang, atau kandang ternak. Bangunan membantu mendukung aktivitas operasional dan pelayanan usaha.',22,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1071,'293f696a-86dd-4e88-bd52-191117652caa',6,'Aset','Detail',3,'1-2030','1-2000','Kendaraan','Debit','Akun ini digunakan untuk mencatat kendaraan operasional milik BUMDes. Kendaraan dipakai untuk distribusi barang, pelayanan usaha, atau kegiatan operasional lainnya. Nilai kendaraan akan menurun seiring umur dan penggunaan.',23,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1072,'aec78d25-6d83-4b56-9f4a-e5a24485c4c4',6,'Aset','Detail',3,'1-2040','1-2000','Peralatan dan Mesin','Debit','Akun ini digunakan untuk mencatat alat kerja dan mesin yang membantu proses usaha. Contohnya mesin produksi, freezer, komputer, atau alat pertanian. Peralatan dan mesin membantu meningkatkan produktivitas usaha BUMDes.',24,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1073,'58db9b9d-83ee-40bd-a326-8801087dac6b',6,'Aset','Detail',3,'1-2050','1-2000','Meubelair/Inventaris','Debit','Akun ini digunakan untuk mencatat perabot dan inventaris kantor atau usaha. Contohnya meja, kursi, lemari, rak display, dan perlengkapan kantor lainnya. Inventaris membantu kegiatan operasional berjalan lebih nyaman dan tertata.',25,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1074,'82c28f65-07e6-4e8b-92a7-106df4326571',6,'Aset','Detail',3,'1-2060','1-2000','Aset Tetap Lainnya','Debit','Akun ini digunakan untuk mencatat aset tetap lain yang belum masuk kelompok tertentu. Biasanya digunakan untuk aset khusus sesuai kebutuhan unit usaha desa. Penggunaan akun ini membuat pencatatan aset lebih fleksibel.',26,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1075,'5f4b5d95-be60-4a6d-beb3-54fe308b675f',6,'Aset','Header',3,'1-2090','1-2000','Akumulasi Penyusutan Aset Tetap','Kredit','Akun ini digunakan untuk mencatat total penurunan nilai aset tetap akibat penggunaan dan umur pakai. Semakin lama aset digunakan, nilai penyusutannya akan semakin besar. Akun ini membantu menunjukkan nilai aset yang masih tersisa.',27,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1076,'40a489d7-075f-4ca5-8b14-95f420e254e0',6,'Aset','Detail',4,'1-2091','1-2090','Akumulasi Penyusutan Bangunan','Kredit','Akun ini mencatat total penurunan nilai bangunan selama digunakan dalam usaha. Nilai bangunan akan berkurang setiap periode sesuai masa manfaatnya. Akun ini membantu menghitung nilai bangunan yang masih tersisa di laporan keuangan.',28,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1077,'35237d0a-74c7-4201-94ae-3b078e6bec76',6,'Aset','Detail',4,'1-2092','1-2090','Akumulasi Penyusutan Kendaraan','Kredit','Akun ini digunakan untuk mencatat total penyusutan kendaraan operasional. Penyusutan terjadi karena kendaraan digunakan dan mengalami penurunan kondisi. Akun ini membantu memperkirakan nilai kendaraan saat ini.',29,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1078,'e4a2fed9-c990-4e38-8c76-ba81e31c0580',6,'Aset','Detail',4,'1-2093','1-2090','Akumulasi Penyusutan Peralatan dan Mesin','Kredit','Akun ini mencatat total penurunan nilai alat dan mesin usaha. Penyusutan dihitung berdasarkan penggunaan dan umur ekonomis alat. Akun ini membantu laporan keuangan menunjukkan nilai alat yang lebih realistis.',30,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1079,'3425b010-2e4d-4f33-b45e-e2763f369e0b',6,'Aset','Detail',4,'1-2094','1-2090','Akumulasi Penyusutan Meubelair/Inventaris','Kredit','Akun ini digunakan untuk mencatat total penyusutan inventaris dan perabot kantor. Semakin lama digunakan, nilai inventaris akan semakin berkurang. Akun ini membantu mengetahui nilai sisa inventaris yang masih dimiliki BUMDes.',31,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1080,'930ba771-d403-4f14-9d1d-bafcee06d321',6,'Aset','Detail',4,'1-2095','1-2090','Akumulasi Penyusutan Aset Tetap Lainnya','Kredit','Akun ini mencatat total penyusutan aset tetap lain di luar kelompok utama. Penyusutan dilakukan agar nilai aset sesuai dengan kondisi sebenarnya. Akun ini membantu menjaga laporan keuangan tetap realistis dan akurat.',32,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1081,'c2ea29b5-0495-454c-92ec-cdfdcae92a3e',6,'Aset','Header',3,'1-3000','1-2000','Aset Lainnya','Debit','Aset lainnya adalah aset yang dimiliki BUMDes tetapi tidak termasuk aset lancar atau aset tetap. Akun ini digunakan untuk mencatat aset yang sifatnya khusus atau tidak sering terjadi. Contohnya investasi jangka panjang atau aset tidak berwujud.',33,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1082,'01eae893-0258-47c7-9f53-c9acf44fc912',6,'Aset','Detail',4,'1-3010','1-3000','Investasi Jangka Panjang','Debit','Akun ini digunakan untuk mencatat dana atau aset yang ditanamkan untuk tujuan jangka panjang. Investasi ini tidak dimaksudkan untuk segera dicairkan dalam waktu dekat. Contohnya penyertaan pada usaha lain atau kerja sama usaha jangka panjang.',34,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1083,'b05fd280-9f40-4e71-a110-dc751209359a',6,'Aset','Detail',4,'1-3020','1-3000','Aset Tak Berwujud','Debit','Aset tak berwujud adalah aset yang tidak memiliki bentuk fisik tetapi memiliki manfaat bagi BUMDes. Contohnya aplikasi, sistem digital, hak cipta, atau hak penggunaan tertentu. Akun ini digunakan jika aset tersebut dianggap memberi manfaat lebih dari satu periode.',35,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1084,'bfb515a3-1f6a-40b3-932c-888ce0021098',6,'Aset','Detail',4,'1-3090','1-3000','Akumulasi Amortisasi Aset Tak Berwujud','Kredit','Akun ini mencatat pengurangan nilai aset tak berwujud dari waktu ke waktu. Sama seperti aset fisik yang mengalami penyusutan, aset tidak berwujud juga dapat berkurang nilai manfaatnya. Akun ini membantu menunjukkan nilai aset tak berwujud yang masih tersisa.',36,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1085,'31931e49-b3e2-4045-8777-5e52fa7128d2',6,'Kewajiban','Header',1,'2-0000','','KEWAJIBAN','Kredit','Kewajiban adalah semua utang atau tanggungan yang masih harus dibayar oleh BUMDes. Kewajiban bisa berasal dari pembelian barang, pinjaman, pajak, gaji, atau tagihan operasional. Akun ini menunjukkan jumlah beban pembayaran yang masih menjadi tanggung jawab BUMDes.',37,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1086,'53ae3260-fae5-42c9-a950-383f7d87f9b2',6,'Kewajiban','Detail',2,'2-0100','2-0000','Utang Usaha','Kredit','Utang usaha adalah tagihan kepada pemasok atau pihak lain karena BUMDes sudah menerima barang atau jasa tetapi belum membayar. Contohnya barang dagangan sudah diterima dari supplier, tetapi pembayarannya dilakukan belakangan. Akun ini membantu memantau kewajiban pembayaran kepada mitra usaha.',38,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1087,'ac82b192-dce5-4354-b82f-ee727720e97b',6,'Kewajiban','Detail',2,'2-0200','2-0000','Utang Gaji/Upah','Kredit','Akun ini digunakan untuk mencatat gaji, honor, atau upah yang sudah menjadi hak pekerja tetapi belum dibayarkan. Misalnya pegawai sudah bekerja bulan ini, tetapi gajinya baru akan dibayar bulan depan. Akun ini membantu BUMDes mengetahui kewajiban kepada tenaga kerja.',39,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1088,'0a0731ef-70aa-4223-8b67-3c7ea4197c4c',6,'Kewajiban','Detail',2,'2-0300','2-0000','Utang Pajak','Kredit','Utang pajak adalah pajak yang sudah menjadi kewajiban BUMDes tetapi belum dibayar ke pihak berwenang. Akun ini digunakan agar kewajiban pajak tidak tercampur dengan biaya lain. Dengan pencatatan ini, BUMDes dapat lebih tertib dalam memenuhi kewajiban perpajakan.',40,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1089,'b9805c3c-8e31-40d1-82f8-96d1b75956be',6,'Kewajiban','Detail',2,'2-0400','2-0000','Utang Utilitas','Kredit','Akun ini digunakan untuk mencatat tagihan listrik, air, internet, telepon, atau pulsa yang belum dibayar. Tagihan tersebut sudah digunakan untuk kegiatan usaha, tetapi pembayarannya belum dilakukan. Akun ini membantu memastikan semua tagihan operasional tetap terpantau.',41,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1090,'3e1f9813-d775-471b-a954-2b8df19c4778',6,'Kewajiban','Detail',2,'2-0500','2-0000','Utang Jangka Pendek Lainnya','Kredit','Akun ini digunakan untuk mencatat utang lain yang harus dibayar dalam waktu dekat. Utang ini belum masuk ke kelompok utang usaha, gaji, pajak, atau utilitas. Akun ini menjadi tempat pencatatan kewajiban jangka pendek yang sifatnya tambahan atau khusus.',42,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1091,'4249c2bf-6ab8-4d9c-9ecb-2c589787575d',6,'Kewajiban','Header',2,'2-1000','2-0000','Kewajiban Jangka Panjang','Kredit','Kewajiban jangka panjang adalah utang atau pinjaman yang masa pembayarannya lebih dari satu tahun. Akun ini biasanya digunakan untuk pinjaman besar atau pembiayaan usaha jangka panjang. Pencatatan ini membantu BUMDes melihat beban pembayaran yang harus direncanakan dalam jangka panjang.',43,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1092,'54c2c6b1-a23b-4437-83b2-a2b78e3c69b6',6,'Kewajiban','Detail',3,'2-1100','2-1000','Utang Bank Jangka Panjang','Kredit','Akun ini mencatat pinjaman dari bank yang jangka waktu pelunasannya lebih dari satu tahun. Contohnya pinjaman untuk pembangunan unit usaha, pembelian kendaraan, atau pengembangan fasilitas. Akun ini membantu memantau sisa pinjaman kepada bank.',44,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1093,'ec47b8cc-954f-42e6-9733-ece85f233b4b',6,'Kewajiban','Detail',3,'2-1200','2-1000','Utang Pihak Ketiga Jangka Panjang','Kredit','Akun ini digunakan untuk mencatat pinjaman jangka panjang dari pihak selain bank. Pihak ketiga bisa berupa lembaga, mitra usaha, koperasi, atau pihak lain yang memberikan pembiayaan. Akun ini membantu membedakan pinjaman bank dan pinjaman non-bank.',45,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1094,'70e1a451-27f9-4715-843b-0279d0af6378',6,'Kewajiban','Detail',3,'2-1300','2-1000','Utang Jangka Panjang Lainnya','Kredit','Akun ini digunakan untuk mencatat kewajiban jangka panjang lain yang belum memiliki kelompok khusus. Akun ini dipakai jika BUMDes memiliki tanggungan pembayaran jangka panjang di luar pinjaman bank atau pihak ketiga. Penggunaan akun ini membuat pencatatan kewajiban lebih fleksibel.',46,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1095,'b26a425e-77d9-4e60-a4ba-50a4fe60664f',6,'Ekuitas','Header',1,'3-0000','','EKUITAS','Kredit','Ekuitas adalah modal dan hak kepemilikan BUMDes atas usaha yang dijalankan. Ekuitas menunjukkan dari mana sumber kekuatan usaha berasal, seperti modal desa, modal masyarakat, bantuan pemerintah, atau laba usaha. Akun ini menggambarkan posisi kekayaan bersih BUMDes setelah dikurangi kewajiban.',47,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1096,'3ab4b7f4-13cd-4fbc-bfc9-a46632298422',6,'Ekuitas','Detail',2,'3-1100','3-0000','Penyertaan Modal Desa','Kredit','Akun ini digunakan untuk mencatat modal yang diberikan oleh pemerintah desa kepada BUMDes. Modal ini biasanya berasal dari penyertaan modal desa yang ditetapkan melalui mekanisme desa. Akun ini penting karena menunjukkan dana publik yang harus dikelola secara bertanggung jawab.',48,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1097,'1deb3932-7905-444f-b952-9a42f1ff2e51',6,'Ekuitas','Detail',2,'3-1200','3-0000','Penyertaan Modal Masyarakat','Kredit','Akun ini digunakan untuk mencatat modal yang berasal dari masyarakat. Modal tersebut dapat berupa penyertaan dana, kontribusi bersama, atau bentuk dukungan lain yang diakui sebagai modal. Akun ini membantu menunjukkan keterlibatan masyarakat dalam pengembangan BUMDes.',49,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1098,'1b213dce-f48b-464b-865e-6dc445d421e4',6,'Ekuitas','Detail',2,'3-1300','3-0000','Penyertaan Modal Bantuan Pemerintah/BKK','Kredit','Akun ini digunakan untuk mencatat modal atau bantuan yang berasal dari pemerintah atau program bantuan tertentu. Bantuan ini dapat digunakan untuk mendukung pengembangan usaha BUMDes. Pencatatan terpisah penting agar sumber dana bantuan dapat dipertanggungjawabkan dengan jelas.',50,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1099,'d2e56d76-094c-4bee-a3c7-1d3648e549d3',6,'Ekuitas','Detail',2,'3-1400','3-0000','Tambahan Penyertaan Modal','Kredit','Akun ini digunakan untuk mencatat tambahan modal yang diberikan setelah modal awal. Tambahan modal bisa berasal dari desa, masyarakat, pemerintah, atau sumber lain yang sah. Akun ini membantu melihat perkembangan dukungan modal dari waktu ke waktu.',51,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1100,'afb8ef7f-cd08-4c7f-b438-bf92191923ad',6,'Ekuitas','Detail',2,'3-1500','3-0000','Laba Ditahan','Kredit','Laba ditahan adalah keuntungan usaha tahun-tahun sebelumnya yang belum dibagikan atau belum digunakan. Dana ini biasanya tetap disimpan untuk memperkuat usaha BUMDes. Akun ini menunjukkan hasil usaha yang masih menjadi bagian dari modal BUMDes.',52,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1101,'905aa9e0-665e-48c6-9eb6-ae0df342fe61',6,'Ekuitas','Detail',2,'3-1600','3-0000','Laba/Rugi Tahun Berjalan','Kredit','Akun ini menunjukkan hasil usaha BUMDes pada tahun berjalan, apakah mengalami keuntungan atau kerugian. Jika pendapatan lebih besar daripada biaya, maka BUMDes memperoleh laba. Jika biaya lebih besar daripada pendapatan, maka BUMDes mengalami rugi.',53,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1102,'146e5e74-dbba-4034-9a35-734b91fc8ac4',6,'Ekuitas','Detail',2,'3-1700','3-0000','Bagi Hasil untuk Desa','Kredit','Akun ini digunakan untuk mencatat bagian hasil usaha yang dialokasikan untuk desa. Bagi hasil ini menunjukkan kontribusi BUMDes terhadap pendapatan atau manfaat bagi desa. Akun ini penting untuk mendukung akuntabilitas kepada pemerintah desa dan masyarakat.',54,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1103,'ba985b88-f40d-4bd6-9744-2045311a9021',6,'Ekuitas','Detail',2,'3-1800','3-0000','Bagi Hasil untuk Masyarakat','Kredit','Akun ini digunakan jika ada bagian hasil usaha yang dialokasikan untuk masyarakat. Pembagian ini dapat terjadi sesuai aturan, kesepakatan, atau model usaha yang melibatkan masyarakat. Akun ini membantu mencatat manfaat langsung BUMDes bagi warga.',55,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1104,'9eb33909-c9f6-4bb7-ab0d-d6141ab24ee5',6,'Ekuitas','Detail',2,'3-1900','3-0000','Ekuitas Lainnya','Kredit','Akun ini digunakan untuk mencatat bagian ekuitas lain yang belum masuk kelompok modal atau laba. Biasanya digunakan untuk kondisi khusus yang berkaitan dengan hak atau kekayaan bersih BUMDes. Akun ini memberi ruang pencatatan yang lebih fleksibel.',56,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1105,'dd0f0d8e-2afe-4e20-bf6d-386727f1458c',6,'Pendapatan','Header',1,'4-0000','','PENDAPATAN USAHA','Kredit','Pendapatan usaha adalah semua penghasilan yang diperoleh BUMDes dari kegiatan usaha utama. Pendapatan ini bisa berasal dari penjualan barang, hasil produksi, jasa, sewa, atau operasional lainnya. Akun ini menunjukkan kemampuan usaha BUMDes dalam menghasilkan uang.',57,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1106,'6531cad7-371a-45ce-8b0b-2063bf05abe4',6,'Pendapatan','Detail',2,'4-1100','4-0000','Pendapatan Penjualan Barang Dagangan','Kredit','Akun ini digunakan untuk mencatat uang masuk dari penjualan barang dagangan. Barang dagangan adalah barang yang dibeli untuk dijual kembali, seperti sembako, gas LPG, pupuk, atau barang minimarket desa. Akun ini cocok untuk unit usaha perdagangan atau desa mart.',58,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1107,'e00bace5-3dc6-444a-8fec-ca01e09199fa',6,'Pendapatan','Detail',2,'4-1200','4-0000','Pendapatan Penjualan Hasil Produksi','Kredit','Akun ini digunakan untuk mencatat pendapatan dari hasil produksi BUMDes. Contohnya penjualan telur, hasil olahan pangan, produk pertanian, atau produk desa lainnya. Akun ini menunjukkan hasil usaha dari kegiatan produksi yang dilakukan BUMDes.',59,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1108,'da284b84-4088-4a88-afe9-0230b73dd33e',6,'Pendapatan','Detail',2,'4-1300','4-0000','Pendapatan Jasa','Kredit','Akun ini digunakan untuk mencatat penghasilan dari layanan jasa yang diberikan BUMDes. Contohnya jasa pembayaran, jasa angkut, jasa cetak, jasa sewa tenaga, atau layanan administrasi tertentu. Akun ini cocok untuk unit usaha yang tidak menjual barang, tetapi menjual layanan.',60,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1109,'6fda5878-3e3c-49c0-999e-2a88380a0650',6,'Pendapatan','Detail',2,'4-1400','4-0000','Pendapatan Sewa','Kredit','Akun ini digunakan untuk mencatat pendapatan dari penyewaan aset atau fasilitas milik BUMDes. Contohnya sewa gedung, sewa kios, sewa alat, sewa kendaraan, atau sewa perlengkapan. Akun ini membantu melihat manfaat ekonomi dari aset yang disewakan.',61,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1110,'5fc06743-99ad-4b06-bd4c-1980463ff075',6,'Pendapatan','Detail',2,'4-1500','4-0000','Pendapatan Denda','Kredit','Akun ini digunakan untuk mencatat pendapatan dari denda yang diterima BUMDes. Contohnya denda keterlambatan pembayaran, keterlambatan pengembalian barang sewaan, atau pelanggaran kesepakatan usaha. Akun ini sebaiknya digunakan hanya jika memang ada aturan denda yang jelas.',62,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1111,'9acf69a5-b38e-4ba6-a6be-c3c0b840d97f',6,'Pendapatan','Detail',2,'4-1600','4-0000','Pendapatan Operasional Lainnya','Kredit','Akun ini digunakan untuk mencatat pendapatan usaha yang masih berkaitan dengan operasional, tetapi tidak masuk kategori utama. Misalnya pendapatan tambahan dari kegiatan usaha yang sifatnya tidak rutin. Akun ini membantu agar semua pendapatan tetap tercatat rapi.',63,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1112,'78316119-497e-4262-8875-76af051304b7',6,'Pendapatan','Header',2,'4-2000','4-0000','Pendapatan Non-Operasional','Kredit','Pendapatan non-operasional adalah penghasilan yang diperoleh di luar kegiatan utama usaha BUMDes. Pendapatan ini bukan berasal dari penjualan rutin barang, jasa, atau produksi. Contohnya bunga bank atau keuntungan dari penjualan aset.',64,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1113,'80978a36-a8f0-40c4-a167-b3a6ca3689f5',6,'Pendapatan','Detail',3,'4-2100','4-2000','Pendapatan Bunga Bank','Kredit','Akun ini digunakan untuk mencatat bunga yang diterima dari rekening bank BUMDes. Pendapatan ini muncul karena BUMDes menyimpan dana di bank. Walaupun nilainya biasanya kecil, pencatatan tetap penting agar saldo dan laporan sesuai.',65,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1114,'e127b67b-68be-41a3-81fb-55640cb1b7dd',6,'Pendapatan','Detail',3,'4-2200','4-2000','Laba Penjualan Aset Tetap','Kredit','Akun ini digunakan jika BUMDes menjual aset tetap dengan harga lebih tinggi daripada nilai bukunya. Contohnya kendaraan lama dijual dan hasil penjualannya lebih besar dari nilai yang tercatat. Selisih keuntungan tersebut dicatat sebagai laba penjualan aset tetap.',66,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1115,'fd143604-0837-4b29-ab0b-ddd8f963ccc4',6,'Pendapatan','Detail',3,'4-2300','4-2000','Pendapatan Lain-lain Non-Operasional','Kredit','Akun ini digunakan untuk mencatat pendapatan lain yang tidak berasal dari kegiatan operasional utama. Contohnya pendapatan insidental atau penerimaan khusus yang jarang terjadi. Akun ini membantu mencatat pemasukan tambahan yang tidak rutin.',67,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1116,'336a7078-4047-433d-88b9-ca1bcd5eb065',6,'Beban/HPP','Header',1,'5-1000','','HARGA POKOK PENJUALAN','Debit','Harga Pokok Penjualan atau HPP adalah biaya utama dari barang atau produk yang dijual. Akun ini membantu menghitung keuntungan kotor usaha. Dengan mengetahui HPP, BUMDes dapat menilai apakah harga jual sudah cukup menguntungkan.',68,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1117,'46c858cf-c607-493b-8ee8-0be422dd0bef',6,'Beban/HPP','Detail',2,'5-1100','5-1000','HPP Barang Dagangan','Debit','Akun ini digunakan untuk mencatat harga beli barang dagangan yang sudah terjual. Misalnya BUMDes membeli sembako untuk dijual kembali, maka biaya barang yang terjual dicatat di akun ini. Akun ini penting untuk menghitung laba dari usaha perdagangan.',69,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1118,'8ff51bfe-8370-4d64-9a91-8a1fa30586dd',6,'Beban/HPP','Detail',2,'5-1200','5-1000','HPP Barang Jadi / Hasil Produksi','Debit','Akun ini digunakan untuk mencatat biaya produksi dari barang jadi yang sudah terjual. Contohnya biaya menghasilkan telur, makanan olahan, atau produk desa lain yang kemudian dijual. Akun ini membantu mengetahui keuntungan dari unit usaha produksi.',70,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1119,'4f50d2c8-d97e-460d-b572-c6c839f4322b',6,'Beban/HPP','Header',1,'5-2000','','BEBAN - BEBAN','Debit','Beban adalah semua biaya yang dikeluarkan untuk menjalankan kegiatan usaha BUMDes. Beban berbeda dengan aset karena manfaatnya biasanya langsung habis dalam periode berjalan. Akun ini membantu melihat seberapa besar biaya yang digunakan untuk menghasilkan pendapatan.',71,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1120,'d2710791-7fc1-4742-a168-724247aabc4d',6,'Beban/HPP','Detail',2,'5-2100','5-2000','Beban Produksi Langsung','Debit','Akun ini digunakan untuk mencatat biaya yang langsung berkaitan dengan proses produksi. Contohnya bahan pendukung, tenaga kerja produksi, atau kebutuhan langsung yang tidak dicatat sebagai persediaan. Akun ini membantu menghitung biaya nyata dalam menghasilkan produk.',72,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1121,'2223c575-f78e-498e-b61a-b49758cc8001',6,'Beban/HPP','Header',2,'5-2200','5-2000','Beban Operasional','Debit','Beban operasional adalah biaya yang digunakan untuk menjalankan kegiatan usaha sehari-hari. Biaya ini mendukung aktivitas unit usaha agar tetap berjalan. Akun ini menjadi kelompok utama untuk biaya operasional BUMDes.',73,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1122,'fe384bcb-f95e-4b1d-9762-5aeb409fc254',6,'Beban/HPP','Detail',3,'5-2210','5-2200','Beban Operasional Peternakan Ayam Petelur','Debit','Akun ini digunakan untuk mencatat biaya operasional unit peternakan ayam petelur. Contohnya pakan, vitamin, obat ternak, tray telur, tenaga harian kandang, dan kebutuhan kandang lainnya. Akun ini membantu mengetahui biaya yang dikeluarkan untuk menjalankan usaha peternakan.',74,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1123,'0b8b1fd5-b91c-4fc4-9a09-7768e5ccbeac',6,'Beban/HPP','Detail',3,'5-2211','5-2200','Beban Operasional Minimarket Desa Mart','Debit','Akun ini digunakan untuk mencatat biaya operasional unit minimarket atau desa mart. Contohnya kantong belanja, display barang, kebersihan toko, perlengkapan kasir, dan kebutuhan toko lainnya. Akun ini membantu menilai efisiensi biaya pada usaha perdagangan ritel.',75,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1124,'c424787c-4ff1-47a1-bce6-6a763541ad11',6,'Beban/HPP','Detail',3,'5-2212','5-2200','Beban Operasional Layanan Jasa Desa Prima','Debit','Akun ini digunakan untuk mencatat biaya operasional unit layanan jasa desa. Contohnya bahan habis pakai jasa, transport operasional, tenaga jasa harian, dan kebutuhan layanan lainnya. Akun ini membantu melihat biaya yang dikeluarkan untuk menghasilkan pendapatan jasa.',76,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1125,'2a4d7a77-3da0-4494-83cf-41484e486513',6,'Beban/HPP','Detail',2,'5-2300','5-2000','Beban Pegawai','Debit','Akun ini digunakan untuk mencatat biaya gaji, honor, upah, atau imbalan kerja pegawai BUMDes. Beban ini muncul karena ada tenaga kerja yang membantu menjalankan usaha. Pencatatan beban pegawai membantu BUMDes mengetahui biaya sumber daya manusia.',77,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1126,'5dfa80f0-fc3f-46cb-8710-ad5af3fee906',6,'Beban/HPP','Detail',2,'5-2400','5-2000','Beban Administrasi dan Umum','Debit','Akun ini digunakan untuk mencatat biaya administrasi dan kebutuhan umum kantor atau usaha. Contohnya alat tulis kantor, fotokopi, legalitas, materai, dan kebutuhan administrasi lainnya. Akun ini mendukung kelancaran kegiatan pengelolaan BUMDes.',78,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1127,'74be3fa2-e61d-47da-a394-b2e72cccf9d2',6,'Beban/HPP','Detail',2,'5-2500','5-2000','Beban Utilitas','Debit','Akun ini digunakan untuk mencatat biaya listrik, air, internet, telepon, dan pulsa. Biaya ini biasanya diperlukan agar kegiatan usaha dan kantor dapat berjalan. Akun ini membantu memantau pengeluaran rutin bulanan.',79,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1128,'055e7c62-bf89-4db1-a64a-0d71d239a503',6,'Beban/HPP','Detail',2,'5-2600','5-2000','Beban Pemeliharaan dan Perbaikan','Debit','Akun ini digunakan untuk mencatat biaya perawatan dan perbaikan aset atau fasilitas usaha. Contohnya servis kendaraan, perbaikan mesin, perbaikan bangunan, atau perawatan peralatan. Akun ini membantu menjaga aset tetap dapat digunakan dengan baik.',80,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1129,'729ad934-242e-4110-b4e5-27007c79aea1',6,'Beban/HPP','Detail',2,'5-2700','5-2000','Beban Perlengkapan','Debit','Akun ini digunakan untuk mencatat perlengkapan yang sudah dipakai dalam kegiatan usaha. Contohnya kertas, tinta, alat kebersihan, kemasan kecil, atau perlengkapan kantor yang habis digunakan. Akun ini menunjukkan biaya dari barang-barang kecil yang mendukung operasional.',81,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1130,'bf9c3d25-6860-4dc2-a72d-2e5a4d977751',6,'Beban/HPP','Detail',2,'5-2800','5-2000','Beban Sewa dan Asuransi','Debit','Akun ini digunakan untuk mencatat biaya sewa dan asuransi yang menjadi beban periode berjalan. Contohnya sewa toko, sewa gudang, sewa alat, atau asuransi kendaraan. Akun ini membantu membedakan biaya sewa/asuransi yang sudah menjadi beban dengan yang masih dibayar di muka.',82,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1131,'724df85c-0f12-48b6-a9e1-a8cf12426c38',6,'Beban/HPP','Detail',2,'5-2900','5-2000','Beban Penyusutan','Debit','Akun ini digunakan untuk mencatat penurunan nilai aset tetap selama digunakan. Contohnya kendaraan, bangunan, mesin, dan inventaris yang nilainya berkurang dari tahun ke tahun. Beban penyusutan membantu laporan menunjukkan biaya pemakaian aset secara wajar.',83,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1132,'96ceeac9-de03-41ea-8baf-9009a729e6a2',6,'Beban/HPP','Detail',2,'5-3000','5-2000','Beban Pajak','Debit','Akun ini digunakan untuk mencatat pajak dan retribusi yang menjadi biaya BUMDes. Contohnya pajak usaha, pajak kendaraan, atau retribusi tertentu. Akun ini membantu memastikan kewajiban pajak dicatat sebagai bagian dari biaya usaha.',84,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1133,'0221a8ac-7741-4f01-a835-b207e7899b47',6,'Beban/HPP','Detail',2,'5-3100','5-2000','Beban Operasional Lainnya','Debit','Akun ini digunakan untuk mencatat biaya operasional lain yang belum masuk kelompok beban sebelumnya. Biasanya digunakan untuk biaya kecil atau khusus yang tetap berhubungan dengan kegiatan usaha. Akun ini menjaga agar semua biaya tetap tercatat meskipun tidak memiliki kategori khusus.',85,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1134,'aaf276ae-004e-49f4-9d1d-141bba748885',6,'Beban/HPP','Header',2,'5-3200','5-2000','Beban Non-Operasional','Debit','Beban non-operasional adalah biaya yang terjadi di luar kegiatan utama usaha BUMDes. Biaya ini tidak langsung berkaitan dengan penjualan barang, produksi, atau jasa utama. Contohnya biaya bank, bunga pinjaman, denda, atau kerugian penjualan aset.',86,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1135,'b83d8775-e7e5-49ff-a3ec-79606b01fc40',6,'Beban/HPP','Detail',3,'5-3201','5-3200','Beban Bank','Debit','Akun ini digunakan untuk mencatat biaya administrasi atau layanan bank. Contohnya potongan administrasi bulanan, biaya transfer, biaya cetak rekening, atau biaya layanan perbankan lainnya. Akun ini membantu mencocokkan saldo pembukuan dengan mutasi rekening bank.',87,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1136,'bda2d1e1-d0b5-4c0f-bcd6-1c4747f5bb4a',6,'Beban/HPP','Detail',3,'5-3202','5-3200','Beban Bunga','Debit','Akun ini digunakan untuk mencatat biaya bunga atas pinjaman atau kredit. Beban bunga muncul karena BUMDes menggunakan dana pinjaman dari bank atau pihak lain. Akun ini membantu melihat biaya tambahan dari pembiayaan usaha.',88,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1137,'dceb59db-97b5-4407-a313-6cb07550ed9a',6,'Beban/HPP','Detail',3,'5-3203','5-3200','Beban Denda','Debit','Akun ini digunakan untuk mencatat biaya denda yang harus dibayar BUMDes. Contohnya denda keterlambatan pembayaran, keterlambatan kewajiban, atau pelanggaran ketentuan tertentu. Akun ini membantu mencatat pengeluaran yang sifatnya tidak rutin dan sebaiknya dikendalikan.',89,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1138,'c4159e02-3e55-4a04-b9d1-2ee6ccb0605e',6,'Beban/HPP','Detail',3,'5-3204','5-3200','Rugi Penjualan Aset Tetap','Debit','Akun ini digunakan jika BUMDes menjual aset tetap dengan harga lebih rendah daripada nilai bukunya. Selisih kerugian tersebut dicatat sebagai rugi penjualan aset tetap. Akun ini membantu menunjukkan dampak keuangan dari pelepasan aset.',90,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010'),(1139,'34d0581f-6010-475c-9d41-beca5da5ce88',6,'Beban/HPP','Detail',3,'5-3205','5-3200','Beban Lain-lain Non-Operasional','Debit','Akun ini digunakan untuk mencatat biaya lain di luar kegiatan operasional utama yang belum memiliki akun khusus. Contohnya pengeluaran insidental atau biaya tidak rutin yang jarang terjadi. Akun ini digunakan sebagai tempat pencatatan terakhir agar semua biaya tetap terdokumentasi.',91,'2026-06-01 09:00:59.010','2026-06-01 09:00:59.010');

--
-- Table structure for table `inventaris`
--

DROP TABLE IF EXISTS `inventaris`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `inventaris` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `slug` char(36) DEFAULT NULL,
  `kode_aset` varchar(50) NOT NULL,
  `profile_bum_des_id` bigint unsigned DEFAULT NULL,
  `unit_usaha_id` bigint unsigned DEFAULT NULL,
  `nama_aset` varchar(150) NOT NULL,
  `merk_aset` varchar(100) DEFAULT NULL,
  `harga_beli` decimal(15,2) DEFAULT '0.00',
  `ongkos_kirim` decimal(15,2) DEFAULT '0.00',
  `biaya_instalasi` decimal(15,2) DEFAULT '0.00',
  `tanggal_pembelian` date DEFAULT NULL,
  `tanggal_digunakan` date DEFAULT NULL,
  `kategori_aset` varchar(100) DEFAULT NULL,
  `umur_ekonomis` bigint DEFAULT '0',
  `aktif` tinyint(1) DEFAULT '1',
  `satuan` varchar(50) DEFAULT NULL,
  `created_at` datetime(3) DEFAULT NULL,
  `updated_at` datetime(3) DEFAULT NULL,
  `nilai_residu` bigint DEFAULT '0',
  `saldo_awal` bigint DEFAULT '0',
  `link_akun_aset_tetap` varchar(255) DEFAULT NULL,
  `akumulasi_penyusutan_awal` bigint DEFAULT '0',
  `link_akun_akumulasi_penyusutan` varchar(255) DEFAULT NULL,
  `status` varchar(50) DEFAULT 'Aktif',
  `kartu_aset_tetap` tinyint(1) DEFAULT '1',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uni_inventaris_kode_aset` (`kode_aset`),
  UNIQUE KEY `idx_inventaris_slug` (`slug`),
  KEY `idx_inventaris_profile_bum_des_id` (`profile_bum_des_id`),
  KEY `idx_inventaris_unit_usaha_id` (`unit_usaha_id`),
  CONSTRAINT `fk_inventaris_profile_bum_des` FOREIGN KEY (`profile_bum_des_id`) REFERENCES `profile_bum_des` (`id`),
  CONSTRAINT `fk_inventaris_unit_usaha` FOREIGN KEY (`unit_usaha_id`) REFERENCES `unit_usahas` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
