--
-- Table structure for table `mapping_transaksis`
--

DROP TABLE IF EXISTS `mapping_transaksis`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `mapping_transaksis` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `slug` char(36) DEFAULT NULL,
  `profile_bum_des_id` bigint unsigned DEFAULT NULL,
  `unit_usaha_id` bigint unsigned DEFAULT NULL,
  `nama_mapping` varchar(255) NOT NULL,
  `kategori_transaksi` enum('masuk','keluar') NOT NULL,
  `akun_debet` varchar(255) DEFAULT NULL,
  `akun_kredit` varchar(255) DEFAULT NULL,
  `keterangan` text,
  `created_at` datetime(3) DEFAULT NULL,
  `updated_at` datetime(3) DEFAULT NULL,
  `tipe_default` enum('tunai','kredit','semua') DEFAULT 'semua',
  `nominal_debet` varchar(100) DEFAULT NULL,
  `nominal_kredit` varchar(100) DEFAULT NULL,
  `link_aset_tetap` tinyint(1) DEFAULT '0',
  `link_persediaan` tinyint(1) DEFAULT '0',
  `link_bk_utang` tinyint(1) DEFAULT '0',
  `link_bk_piutang` tinyint(1) DEFAULT '0',
  `link_jurnal_penyesuaian` tinyint(1) DEFAULT '0',
  `klasifikasi_arus_kas` varchar(100) DEFAULT NULL,
  `cash_in_out` varchar(50) DEFAULT NULL,
  `kategori_arus_kas` varchar(255) DEFAULT NULL,
  `jenis_mapping` varchar(30) DEFAULT 'harian',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_mapping_transaksis_slug` (`slug`),
  KEY `idx_mapping_transaksis_profile_bum_des_id` (`profile_bum_des_id`),
  KEY `idx_mapping_transaksis_unit_usaha_id` (`unit_usaha_id`),
  KEY `idx_mapping_transaksis_jenis_mapping` (`jenis_mapping`),
  CONSTRAINT `fk_mapping_transaksis_profile_bum_des` FOREIGN KEY (`profile_bum_des_id`) REFERENCES `profile_bum_des` (`id`),
  CONSTRAINT `fk_mapping_transaksis_unit_usaha` FOREIGN KEY (`unit_usaha_id`) REFERENCES `unit_usahas` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=925 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

