--
-- Table structure for table `pelanggans`
--

DROP TABLE IF EXISTS `pelanggans`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pelanggans` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `kode_pelanggan` varchar(50) NOT NULL,
  `nama_pelanggan` varchar(150) NOT NULL,
  `alamat` text,
  `no_telepon` varchar(20) NOT NULL,
  `created_at` datetime(3) DEFAULT NULL,
  `updated_at` datetime(3) DEFAULT NULL,
  `slug` char(36) DEFAULT NULL,
  `unit_usaha_id` bigint unsigned DEFAULT NULL,
  `profile_bum_des_id` bigint unsigned DEFAULT NULL,
  `status` varchar(20) DEFAULT 'Aktif',
  `saldo_awal` bigint DEFAULT '0',
  `bk_pembantu_piutang` tinyint(1) DEFAULT '0',
  `link_akun` varchar(150) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uni_pelanggans_kode_pelanggan` (`kode_pelanggan`),
  UNIQUE KEY `idx_pelanggans_slug` (`slug`),
  KEY `idx_pelanggans_unit_usaha_id` (`unit_usaha_id`),
  KEY `idx_pelanggans_profile_bum_des_id` (`profile_bum_des_id`),
  CONSTRAINT `fk_pelanggans_profile_bum_des` FOREIGN KEY (`profile_bum_des_id`) REFERENCES `profile_bum_des` (`id`),
  CONSTRAINT `fk_pelanggans_unit_usaha` FOREIGN KEY (`unit_usaha_id`) REFERENCES `unit_usahas` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=88 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

