INSERT INTO `profile_bum_des` VALUES (6,'BUMDes Maju Sejahtera Mandiri','Jl. Raya Desa Pulotondo No. 15, Kecamatan Ngunut, Kabupaten Tulungagung, Jawa Timur','081234567890','BUMDes/PMD/2026/001','','td {border: 1px solid #cccccc;}br {mso-data-placement:same-cell;}Menjadi BUMDes yang mandiri, profesional, dan mampu meningkatkan kesejahteraan masyarakat desa melalui pengelolaan usaha yang transparan dan berkelanjutan.','td {border: 1px solid #cccccc;}br {mso-data-placement:same-cell;}Mengembangkan unit usaha desa yang sesuai dengan potensi lokal.td {border: 1px solid #cccccc;}br {mso-data-placement:same-cell;}Meningkatkan pendapatan asli desa melalui kegiatan usaha produktif.td {border: 1px solid #cccccc;}br {mso-data-placement:same-cell;}Menyediakan layanan ekonomi yang bermanfaat bagi masyarakat desa.td {border: 1px solid #cccccc;}br {mso-data-placement:same-cell;}Menerapkan sistem pencatatan dan pelaporan keuangan yang tertib, akuntabel, dan transparan.td {border: 1px solid #cccccc;}br {mso-data-placement:same-cell;}Mendorong partisipasi masyarakat dalam pengembangan ekonomi desa.<br>','Arif Santoso','Rina Wulandari','Siti Aminah','Dwi Prasetyo','Hadi Suwarno','2026-01-01 07:00:00.000','2026-12-30 07:00:00.000','2026-05-16 04:48:10.940','2026-06-08 22:12:49.232','a45fa23c-87e3-4797-8ef8-539be57515ce'),(7,'Luqman','gpa','081333282900','124','','visi','misi','Luqman','Affandi','Dian','Wahyuningsih','mboh','2026-06-01 07:00:00.000','2026-06-01 07:00:00.000','2026-06-01 09:02:48.028','2026-06-01 09:02:48.028','4cf4d335-17e1-4a29-bae4-0ea0711ea217');

