-- Table structure for table `suppliers`
--

DROP TABLE IF EXISTS `suppliers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `suppliers` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `slug` char(36) DEFAULT NULL,
  `kode_supplier` varchar(50) NOT NULL,
  `profile_bum_des_id` bigint unsigned DEFAULT NULL,
  `unit_usaha_id` bigint unsigned DEFAULT NULL,
  `nama_supplier` varchar(150) NOT NULL,
  `alamat` text,
  `no_telepon` varchar(20) NOT NULL,
  `created_at` datetime(3) DEFAULT NULL,
  `updated_at` datetime(3) DEFAULT NULL,
  `bidang_supply` varchar(150) DEFAULT NULL,
  `status` varchar(20) DEFAULT 'Aktif',
  `saldo_awal` bigint DEFAULT '0',
  `bk_pembantu_utang` tinyint(1) DEFAULT '0',
  `link_akun` varchar(150) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uni_suppliers_kode_supplier` (`kode_supplier`),
  UNIQUE KEY `idx_suppliers_slug` (`slug`),
  KEY `idx_suppliers_profile_bum_des_id` (`profile_bum_des_id`),
  KEY `idx_suppliers_unit_usaha_id` (`unit_usaha_id`),
  CONSTRAINT `fk_suppliers_profile_bum_des` FOREIGN KEY (`profile_bum_des_id`) REFERENCES `profile_bum_des` (`id`),
  CONSTRAINT `fk_suppliers_unit_usaha` FOREIGN KEY (`unit_usaha_id`) REFERENCES `unit_usahas` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

